  { id: 79, fr: "Ça ne me dit rien du tout, on pourrait faire autre chose ?", en: "I don't feel like it at all, could we do something else?", context: "Declining politely", alt_usage: "Ce film ne me dit rien, tu as une autre suggestion ?", alt_usage_en: "I don't feel like that movie, do you have another suggestion?" },
  { id: 80, fr: "J'ai la flemme de cuisiner ce soir, on commande quelque chose ?", en: "I can't be bothered to cook tonight, shall we order something?", context: "Casual suggestion", alt_usage: "J'ai la flemme de sortir, on reste à la maison ?", alt_usage_en: "I can't be bothered to go out, shall we stay home?" },
  { id: 81, fr: "Tu pourrais me rendre un petit service, si ça ne t'embête pas ?", en: "Could you do me a small favor, if you don't mind?", context: "Asking a favor", alt_usage: "Si ça ne t'embête pas, tu pourrais baisser la musique ?", alt_usage_en: "If you don't mind, could you turn down the music?" },
  { id: 82, fr: "Ça tombe bien, j'allais justement t'en parler.", en: "Perfect timing, I was just about to bring that up.", context: "Happy coincidence", alt_usage: "Ça tombe bien que tu sois là, j'ai besoin d'un coup de main.", alt_usage_en: "Perfect timing that you're here, I need a hand." },
  { id: 83, fr: "Je me suis trompé de rue, je suis complètement perdu.", en: "I took the wrong street, I'm completely lost.", context: "Being lost", alt_usage: "Je me suis trompé de date, la fête c'est samedi prochain.", alt_usage_en: "I got the date wrong, the party is next Saturday." },
  { id: 84, fr: "Il fait un froid de canard, on ferait mieux de rentrer.", en: "It's freezing cold, we'd better go back inside.", context: "Commenting on weather", alt_usage: "Il fait un froid de canard dehors, prends ton écharpe.", alt_usage_en: "It's freezing cold outside, take your scarf." },
  { id: 85, fr: "Je ne suis pas d'humeur à sortir ce soir, une autre fois peut-être.", en: "I'm not in the mood to go out tonight, another time maybe.", context: "Declining an invitation", alt_usage: "Je ne suis pas d'humeur à discuter de ça maintenant.", alt_usage_en: "I'm not in the mood to discuss that right now." },
  { id: 86, fr: "On est arrivés pile à l'heure, pour une fois.", en: "We arrived right on time, for once.", context: "Noting punctuality", alt_usage: "Le bus est arrivé pile à l'heure, c'est un miracle.", alt_usage_en: "The bus arrived right on time, it's a miracle." },
  { id: 87, fr: "Ce n'est pas grave, ça arrive à tout le monde.", en: "It's no big deal, it happens to everyone.", context: "Reassuring", alt_usage: "Tu as renversé ton café ? Ce n'est pas grave, ça arrive.", alt_usage_en: "You spilled your coffee? It's no big deal, it happens." },
  { id: 88, fr: "J'ai un trou de mémoire, ça me reviendra.", en: "I'm having a memory lapse, it'll come back to me.", context: "Forgetting something", alt_usage: "Son nom ? J'ai un trou de mémoire, attends deux secondes.", alt_usage_en: "His name? I'm having a memory lapse, give me two seconds." },

  // ── Work & Professional ─────────────────────────────────
  { id: 89, fr: "Je me permets de revenir vers vous au sujet de notre dernier échange.", en: "I'm getting back to you regarding our last conversation.", context: "Professional follow-up", alt_usage: "Je reviens vers vous pour confirmer notre rendez-vous de jeudi.", alt_usage_en: "I'm getting back to you to confirm our Thursday meeting." },
  { id: 90, fr: "Ça ne relève pas de mes compétences, mais je peux te mettre en contact.", en: "That's outside my area, but I can put you in touch with someone.", context: "Redirecting", alt_usage: "Ce dossier ne relève pas de mon service, adressez-vous à la comptabilité.", alt_usage_en: "This file doesn't fall under my department, contact accounting." },
  { id: 91, fr: "On est débordés en ce moment, il va falloir prioriser.", en: "We're swamped right now, we'll need to prioritize.", context: "Managing workload", alt_usage: "On est débordés avec le lancement, ça peut attendre la semaine prochaine ?", alt_usage_en: "We're swamped with the launch, can it wait until next week?" },
  { id: 92, fr: "J'ai pris du retard sur ce dossier, je m'en excuse.", en: "I've fallen behind on this file, I apologize.", context: "Professional apology", alt_usage: "J'ai pris du retard à cause d'un imprévu, je vous envoie ça demain.", alt_usage_en: "I've fallen behind due to something unexpected, I'll send it to you tomorrow." },
  { id: 93, fr: "Sauf erreur de ma part, on avait convenu d'un autre arrangement.", en: "Unless I'm mistaken, we had agreed on a different arrangement.", context: "Politely correcting", alt_usage: "Sauf erreur de ma part, la réunion était prévue à quatorze heures.", alt_usage_en: "Unless I'm mistaken, the meeting was scheduled for two o'clock." },
  { id: 94, fr: "Je fais au mieux, mais je ne peux pas tout gérer tout seul.", en: "I'm doing my best, but I can't handle everything on my own.", context: "Setting limits", alt_usage: "Je fais au mieux avec les ressources qu'on a, soyez patients.", alt_usage_en: "I'm doing my best with the resources we have, be patient." },
  { id: 95, fr: "Ce n'est pas dans mes habitudes de me plaindre, mais là c'est trop.", en: "I don't usually complain, but this is too much.", context: "Lodging a complaint", alt_usage: "Ce n'est pas dans mes habitudes d'arriver en retard, désolé.", alt_usage_en: "It's not like me to arrive late, sorry." },
  { id: 96, fr: "N'hésitez pas à me relancer si vous n'avez pas de retour de ma part.", en: "Don't hesitate to follow up if you don't hear back from me.", context: "Professional courtesy", alt_usage: "N'hésitez pas à me relancer, je suis parfois débordé de courriels.", alt_usage_en: "Don't hesitate to follow up, I'm sometimes swamped with emails." },

  // ── Idiomatic Expressions ───────────────────────────────
  { id: 97, fr: "On n'est pas sortis de l'auberge.", en: "We're not out of the woods yet.", context: "Acknowledging ongoing difficulty", alt_usage: "Avec tous ces problèmes techniques, on n'est pas sortis de l'auberge.", alt_usage_en: "With all these technical problems, we're not out of the woods yet." },
  { id: 98, fr: "Ce n'est pas la mer à boire, tu vas y arriver.", en: "It's not the end of the world, you'll manage.", context: "Encouraging", alt_usage: "Remplir ce formulaire, ce n'est pas la mer à boire.", alt_usage_en: "Filling out this form isn't the end of the world." },
  { id: 99, fr: "Il ne faut pas mettre la charrue avant les bœufs.", en: "We shouldn't put the cart before the horse.", context: "Urging patience", alt_usage: "Tu parles déjà de promotion ? Ne mets pas la charrue avant les bœufs.", alt_usage_en: "You're already talking about a promotion? Don't put the cart before the horse." },
  { id: 100, fr: "Autant chercher une aiguille dans une botte de foin.", en: "It's like looking for a needle in a haystack.", context: "Describing futility", alt_usage: "Retrouver ce document sans le nom exact, c'est une aiguille dans une botte de foin.", alt_usage_en: "Finding that document without the exact name is like a needle in a haystack." },
  { id: 101, fr: "Il vaut mieux tard que jamais, comme on dit.", en: "Better late than never, as they say.", context: "Philosophical acceptance", alt_usage: "Tu t'es enfin inscrit au sport ? Mieux vaut tard que jamais !", alt_usage_en: "You finally signed up for sports? Better late than never!" },
  { id: 102, fr: "C'est en forgeant qu'on devient forgeron.", en: "Practice makes perfect.", context: "Encouraging persistence", alt_usage: "Continue à t'entraîner, c'est en forgeant qu'on devient forgeron.", alt_usage_en: "Keep practicing, practice makes perfect." },
  { id: 103, fr: "Après la pluie, le beau temps.", en: "Every cloud has a silver lining.", context: "Offering comfort", alt_usage: "Ne t'inquiète pas pour cette mauvaise passe, après la pluie le beau temps.", alt_usage_en: "Don't worry about this rough patch, every cloud has a silver lining." },
  { id: 104, fr: "Il ne faut pas vendre la peau de l'ours avant de l'avoir tué.", en: "Don't count your chickens before they hatch.", context: "Warning against premature celebration", alt_usage: "On n'a pas encore signé le contrat, ne vendons pas la peau de l'ours.", alt_usage_en: "We haven't signed the contract yet, don't count your chickens." },
  { id: 105, fr: "Qui vivra verra, ce n'est pas la peine de spéculer.", en: "Time will tell, there's no point speculating.", context: "Philosophical patience", alt_usage: "Est-ce que ça marchera ? Qui vivra verra.", alt_usage_en: "Will it work? Time will tell." },
  { id: 106, fr: "On ne fait pas d'omelette sans casser des œufs.", en: "You can't make an omelette without breaking eggs.", context: "Accepting trade-offs", alt_usage: "Il y aura des mécontents, mais on ne fait pas d'omelette sans casser des œufs.", alt_usage_en: "There will be unhappy people, but you can't make an omelette without breaking eggs." },

  // ── Nuanced / Sophisticated ─────────────────────────────
  { id: 107, fr: "Il y a anguille sous roche, je ne lui fais pas confiance.", en: "Something's fishy, I don't trust him.", context: "Expressing suspicion", alt_usage: "Ce prix est trop bas, il y a anguille sous roche.", alt_usage_en: "That price is too low, something's fishy." },
  { id: 108, fr: "C'est à double tranchant, il faut peser le pour et le contre.", en: "It's a double-edged sword, we need to weigh the pros and cons.", context: "Analyzing risk", alt_usage: "Les réseaux sociaux, c'est à double tranchant pour les ados.", alt_usage_en: "Social media is a double-edged sword for teenagers." },
  { id: 109, fr: "Je marche sur des œufs avec ce sujet, c'est très délicat.", en: "I'm walking on eggshells with this topic, it's very sensitive.", context: "Navigating sensitivity", alt_usage: "Avec mon nouveau patron, je marche sur des œufs en permanence.", alt_usage_en: "With my new boss, I'm constantly walking on eggshells." },
  { id: 110, fr: "On remet les pendules à l'heure : voilà ce qui s'est vraiment passé.", en: "Let's set the record straight: here's what actually happened.", context: "Correcting a narrative", alt_usage: "Remettons les pendules à l'heure, c'est moi qui ai proposé cette idée.", alt_usage_en: "Let's set the record straight, I'm the one who proposed that idea." },
  { id: 111, fr: "Ça sent le roussi, je crois qu'on va avoir des problèmes.", en: "I smell trouble, I think we're going to have problems.", context: "Sensing danger", alt_usage: "Quand le directeur convoque tout le monde, ça sent le roussi.", alt_usage_en: "When the director calls everyone in, I smell trouble." },
  { id: 112, fr: "Il a retourné sa veste du jour au lendemain, sans la moindre explication.", en: "He did a complete U-turn overnight, without the slightest explanation.", context: "Describing betrayal", alt_usage: "Ce politicien a retourné sa veste dès qu'il a été élu.", alt_usage_en: "That politician did a complete U-turn as soon as he was elected." },
  { id: 113, fr: "Ce n'est que la partie visible de l'iceberg.", en: "That's just the tip of the iceberg.", context: "Suggesting hidden depth", alt_usage: "Ces quelques erreurs ne sont que la partie visible de l'iceberg.", alt_usage_en: "These few mistakes are just the tip of the iceberg." },
  { id: 114, fr: "Il a le don de mettre les pieds dans le plat.", en: "He has a knack for putting his foot in his mouth.", context: "Describing tactlessness", alt_usage: "Ne l'invite pas au dîner, il met toujours les pieds dans le plat.", alt_usage_en: "Don't invite him to dinner, he always puts his foot in his mouth." },
  { id: 115, fr: "On a tourné la page, il est temps de passer à autre chose.", en: "We've turned the page, it's time to move on.", context: "Closure", alt_usage: "Après le divorce, elle a tourné la page et recommencé sa vie.", alt_usage_en: "After the divorce, she turned the page and started her life over." },
  { id: 116, fr: "Mieux vaut prévenir que guérir, surtout dans ce genre de situation.", en: "Better safe than sorry, especially in this kind of situation.", context: "Advocating caution", alt_usage: "Fais une sauvegarde de tes fichiers, mieux vaut prévenir que guérir.", alt_usage_en: "Back up your files, better safe than sorry." },
  { id: 117, fr: "Je donne ma langue au chat, je ne vois vraiment pas.", en: "I give up, I really can't figure it out.", context: "Admitting defeat", alt_usage: "C'est quoi la réponse ? Je donne ma langue au chat.", alt_usage_en: "What's the answer? I give up." },
  { id: 118, fr: "Il faut battre le fer tant qu'il est chaud.", en: "We need to strike while the iron is hot.", context: "Urging timely action", alt_usage: "Il est intéressé par notre offre, battons le fer tant qu'il est chaud.", alt_usage_en: "He's interested in our offer, let's strike while the iron is hot." },
  { id: 119, fr: "Les murs ont des oreilles, fais attention à ce que tu dis.", en: "The walls have ears, be careful what you say.", context: "Warning about eavesdropping", alt_usage: "Pas ici, les murs ont des oreilles. On en parle dehors.", alt_usage_en: "Not here, the walls have ears. Let's talk outside." },
  { id: 120, fr: "J'ai d'autres chats à fouetter pour le moment.", en: "I have bigger fish to fry right now.", context: "Expressing priorities", alt_usage: "Je ne peux pas m'occuper de ça, j'ai d'autres chats à fouetter.", alt_usage_en: "I can't deal with that, I have bigger fish to fry." },
  { id: 121, fr: "Ça ne casse pas trois pattes à un canard, mais c'est correct.", en: "It's nothing special, but it's decent.", context: "Lukewarm praise", alt_usage: "Le restaurant était bon, sans casser trois pattes à un canard.", alt_usage_en: "The restaurant was good, nothing special though." },
  { id: 122, fr: "Il pleut des cordes, on ferait mieux de rester ici.", en: "It's raining cats and dogs, we'd better stay here.", context: "Weather decision", alt_usage: "Prends un parapluie, il pleut des cordes depuis ce matin.", alt_usage_en: "Take an umbrella, it's been raining cats and dogs since this morning." },
  { id: 123, fr: "Je n'y suis pour rien, c'est pas moi qui ai décidé.", en: "It's not my fault, I'm not the one who decided.", context: "Deflecting blame", alt_usage: "Si le projet a échoué, je n'y suis pour rien.", alt_usage_en: "If the project failed, it's not my fault." },
  { id: 124, fr: "C'est un coup d'épée dans l'eau, ça ne changera rien.", en: "It's a waste of effort, it won't change anything.", context: "Futility", alt_usage: "Se plaindre au service client, c'est un coup d'épée dans l'eau.", alt_usage_en: "Complaining to customer service is a waste of effort." },
  { id: 125, fr: "On fera avec les moyens du bord.", en: "We'll make do with what we've got.", context: "Pragmatic acceptance", alt_usage: "Le budget est serré, mais on fera avec les moyens du bord.", alt_usage_en: "The budget is tight, but we'll make do with what we've got." },
  { id: 126, fr: "Prenons le taureau par les cornes et réglons ça maintenant.", en: "Let's take the bull by the horns and sort this out now.", context: "Decisive action", alt_usage: "Au lieu d'attendre, prends le taureau par les cornes et appelle-le.", alt_usage_en: "Instead of waiting, take the bull by the horns and call him." },
  { id: 127, fr: "Ce n'est pas tombé dans l'oreille d'un sourd.", en: "It didn't fall on deaf ears.", context: "Confirming attention", alt_usage: "Ton conseil n'est pas tombé dans l'oreille d'un sourd, j'ai agi.", alt_usage_en: "Your advice didn't fall on deaf ears, I took action." },
  { id: 128, fr: "Il faut savoir raison garder, même quand c'est difficile.", en: "We must keep a level head, even when it's hard.", context: "Advocating composure", alt_usage: "Gardons raison, la panique ne résoudra rien.", alt_usage_en: "Let's keep a level head, panicking won't solve anything." },
  { id: 129, fr: "Tant pis, ce sera pour une autre fois.", en: "Too bad, it'll be for another time.", context: "Accepting a missed opportunity", alt_usage: "Le concert est complet ? Tant pis, ce sera pour une autre fois.", alt_usage_en: "The concert is sold out? Too bad, it'll be for another time." },
  // ── User-supplied ──────────────────────────────────────
  { id: 130, fr: "Mêle-toi de tes oignons.", en: "Mind your own business.", context: "Telling someone to back off", alt_usage: "Arrête de fouiller dans mes affaires, mêle-toi de tes oignons !", alt_usage_en: "Stop digging through my things, mind your own business!" },
  { id: 131, fr: "Elle cache bien son jeu, dis donc.", en: "She really hides her cards, doesn't she.", context: "Noting hidden intentions", alt_usage: "Il cache bien son jeu, on ne sait jamais ce qu'il pense vraiment.", alt_usage_en: "He really hides his cards, you never know what he really thinks." },
  { id: 132, fr: "Je comptais t'en parler.", en: "I was planning to tell you about it.", context: "Pre-empting a question", alt_usage: "Je comptais t'en parler ce soir, justement.", alt_usage_en: "I was actually planning to tell you about it tonight." },
  { id: 133, fr: "Ça t'embêterait de me donner un coup de main pour ranger les courses ?", en: "Would you mind giving me a hand putting away the groceries?", context: "Polite request for help", alt_usage: "Ça t'embêterait de me déposer à la gare en passant ?", alt_usage_en: "Would you mind dropping me off at the station on your way?" },
  { id: 134, fr: "Je m'en serais souvenu.", en: "I would have remembered that.", context: "Denying having heard something", alt_usage: "Si tu me l'avais dit, je m'en serais souvenu, crois-moi.", alt_usage_en: "If you had told me, I would have remembered, trust me." },
  { id: 135, fr: "Je ne pense pas t'avoir jamais vu rire.", en: "I don't think I've ever seen you laugh.", context: "Observing a personality trait", alt_usage: "Je ne pense pas t'avoir jamais entendu te plaindre.", alt_usage_en: "I don't think I've ever heard you complain." },
  // ── New: Social & politeness ───────────────────────────
  { id: 136, fr: "Je ne voudrais pas abuser, mais tu pourrais me rendre un dernier service ?", en: "I don't want to take advantage, but could you do me one last favor?", context: "Tentative request", alt_usage: "Je ne voudrais pas abuser, mais est-ce que je peux rester une nuit de plus ?", alt_usage_en: "I don't want to take advantage, but can I stay one more night?" },
  { id: 137, fr: "Fais comme chez toi, sers-toi ce que tu veux.", en: "Make yourself at home, help yourself to whatever you want.", context: "Welcoming a guest", alt_usage: "Entre, fais comme chez toi, je finis dans la cuisine.", alt_usage_en: "Come in, make yourself at home, I'm finishing up in the kitchen." },
  { id: 138, fr: "On se tient au courant, hein ?", en: "We'll keep in touch, alright?", context: "Casual goodbye", alt_usage: "Tiens-moi au courant dès que tu as des nouvelles.", alt_usage_en: "Keep me posted as soon as you hear anything." },
  { id: 139, fr: "Je passe juste en coup de vent, je ne peux pas rester.", en: "I'm just dropping by briefly, I can't stay.", context: "Quick visit", alt_usage: "Désolé, c'était un coup de vent, je file maintenant.", alt_usage_en: "Sorry, that was a quick stop, I'm off now." },
  { id: 140, fr: "Je ne te dérange pas, j'espère ?", en: "I'm not disturbing you, I hope?", context: "Checking before starting a conversation", alt_usage: "J'espère que je ne te dérange pas en pleine réunion.", alt_usage_en: "I hope I'm not disturbing you in the middle of a meeting." },
  { id: 141, fr: "Tu tombes bien, j'allais justement t'appeler.", en: "Perfect timing, I was just about to call you.", context: "Unexpected good timing", alt_usage: "Tu tombes mal, je suis en pleine réunion.", alt_usage_en: "Bad timing, I'm in the middle of a meeting." },
  { id: 142, fr: "On ne va pas y passer la nuit non plus.", en: "We're not going to spend all night on this.", context: "Suggesting to wrap up", alt_usage: "Décide-toi, on ne va pas y passer la nuit.", alt_usage_en: "Make up your mind, we're not going to spend all night on this." },
  { id: 143, fr: "Je file, on m'attend.", en: "I'm off, someone's waiting for me.", context: "Hurried departure", alt_usage: "Bon, je file, à demain !", alt_usage_en: "Right, I'm off, see you tomorrow!" },
  // ── New: Opinion & agreement ───────────────────────────
  { id: 144, fr: "Là, je te suis complètement.", en: "On that, I'm completely with you.", context: "Strong agreement", alt_usage: "Sur ce point précis, je te suis à cent pour cent.", alt_usage_en: "On that specific point, I'm with you a hundred percent." },
  { id: 145, fr: "Je ne dis pas le contraire, mais il y a des nuances.", en: "I'm not saying otherwise, but there's nuance.", context: "Partial agreement", alt_usage: "Je ne dis pas le contraire, c'est juste plus compliqué que ça.", alt_usage_en: "I'm not saying otherwise, it's just more complicated than that." },
  { id: 146, fr: "Ça se discute, franchement.", en: "That's debatable, honestly.", context: "Polite disagreement", alt_usage: "Que ce soit la meilleure solution, ça se discute.", alt_usage_en: "Whether that's the best solution is debatable." },
  { id: 147, fr: "Tu n'as pas tort, mais tu n'as pas tout à fait raison non plus.", en: "You're not wrong, but you're not quite right either.", context: "Hedging", alt_usage: "Tu n'as pas tort de t'inquiéter, mais ne dramatise pas.", alt_usage_en: "You're not wrong to worry, but don't dramatize it." },
  { id: 148, fr: "C'est tout à fait ça, tu as mis le doigt dessus.", en: "That's exactly it, you've put your finger on it.", context: "Confirming insight", alt_usage: "Tu as mis le doigt sur le vrai problème, là.", alt_usage_en: "You've put your finger on the real problem there." },
  { id: 149, fr: "Je n'irais pas jusque-là.", en: "I wouldn't go that far.", context: "Tempering an overstatement", alt_usage: "Dire qu'il est génial, je n'irais pas jusque-là.", alt_usage_en: "Saying he's brilliant, I wouldn't go that far." },
  // ── New: Emotion ───────────────────────────────────────
  { id: 150, fr: "Ça me fait une belle jambe.", en: "A lot of good that does me.", context: "Sarcastic dismissal", alt_usage: "Il s'excuse maintenant ? Ça me fait une belle jambe.", alt_usage_en: "He's apologizing now? A lot of good that does me." },
  { id: 151, fr: "J'en reviens pas, sérieux.", en: "I can't get over it, seriously.", context: "Shock and disbelief", alt_usage: "Elle a vraiment dit ça ? J'en reviens pas.", alt_usage_en: "She actually said that? I can't get over it." },
  { id: 152, fr: "Ça me prend la tête, ce truc.", en: "This thing is doing my head in.", context: "Frustration with a problem", alt_usage: "Arrête, ça me prend la tête depuis ce matin.", alt_usage_en: "Stop, this has been doing my head in since morning." },
  { id: 153, fr: "Je suis sur les nerfs, là.", en: "My nerves are shot right now.", context: "Stressed state", alt_usage: "Ne me parle pas tout de suite, je suis sur les nerfs.", alt_usage_en: "Don't talk to me right now, my nerves are shot." },
  { id: 154, fr: "Ouf, j'ai eu chaud !", en: "Phew, that was close!", context: "Narrow escape", alt_usage: "Le train est parti juste après moi, j'ai eu chaud.", alt_usage_en: "The train left right after me, that was close." },
  { id: 155, fr: "Ça me touche, vraiment, merci.", en: "That really moves me, thank you.", context: "Heartfelt gratitude", alt_usage: "Ton geste me touche beaucoup, c'est rare.", alt_usage_en: "Your gesture moves me a lot, that's rare." },
  // ── New: Narration & storytelling ──────────────────────
  { id: 156, fr: "Bref, tout ça pour dire que j'avais raison.", en: "Anyway, all that to say I was right.", context: "Wrapping up a story", alt_usage: "Bref, tout ça pour dire qu'il faut qu'on parte tôt.", alt_usage_en: "Anyway, all that to say we have to leave early." },
  { id: 157, fr: "Figure-toi que je l'ai croisé hier dans la rue.", en: "Get this — I ran into him in the street yesterday.", context: "Sharing surprising news", alt_usage: "Figure-toi qu'elle a démissionné sans prévenir.", alt_usage_en: "Get this — she quit without warning." },
  { id: 158, fr: "Et là, tiens-toi bien, il me sort qu'il a tout oublié.", en: "And then, brace yourself, he tells me he forgot everything.", context: "Building suspense in a story", alt_usage: "Et là, tiens-toi bien, elle débarque avec son ex !", alt_usage_en: "And then, brace yourself, she shows up with her ex!" },
  { id: 159, fr: "Pour faire court, ça s'est mal terminé.", en: "Long story short, it ended badly.", context: "Summarizing", alt_usage: "Pour faire court, on a manqué notre vol.", alt_usage_en: "Long story short, we missed our flight." },
  { id: 160, fr: "Sur le coup, je n'ai pas réagi.", en: "In the moment, I didn't react.", context: "Recalling a delayed reaction", alt_usage: "Sur le coup, je n'ai rien compris, c'est venu après.", alt_usage_en: "In the moment, I didn't get it, it came to me later." },
  { id: 161, fr: "À l'époque, on faisait comme on pouvait.", en: "Back then, we did what we could.", context: "Reflecting on the past", alt_usage: "À l'époque, il n'y avait même pas de portables.", alt_usage_en: "Back then, there weren't even cell phones." },
  // ── New: Argument & persuasion ─────────────────────────
  { id: 162, fr: "Mets-toi à ma place deux secondes.", en: "Put yourself in my shoes for two seconds.", context: "Asking for empathy", alt_usage: "Mets-toi à sa place, ce n'est pas facile pour lui non plus.", alt_usage_en: "Put yourself in his shoes, it's not easy for him either." },
  { id: 163, fr: "Tu vois ce que je veux dire ?", en: "You see what I mean?", context: "Checking understanding", alt_usage: "C'est un peu spécial comme situation, tu vois ce que je veux dire.", alt_usage_en: "It's a bit of a peculiar situation, you see what I mean." },
  { id: 164, fr: "On en reparle quand tu seras calmé.", en: "We'll talk again once you've calmed down.", context: "Postponing a heated discussion", alt_usage: "On en reparle demain, là on est tous fatigués.", alt_usage_en: "We'll talk again tomorrow, right now we're all tired." },
  { id: 165, fr: "Soyons clairs : ce n'est pas négociable.", en: "Let's be clear: this isn't up for debate.", context: "Setting a firm boundary", alt_usage: "Soyons clairs, je ne reviendrai pas sur ma décision.", alt_usage_en: "Let's be clear, I'm not going to reconsider my decision." },
  { id: 166, fr: "Tu ne vas pas en faire toute une histoire.", en: "You're not going to make a whole thing out of it.", context: "Asking someone not to overreact", alt_usage: "C'est juste un retard, n'en fais pas toute une histoire.", alt_usage_en: "It's just a delay, don't make a whole thing out of it." },
  { id: 167, fr: "Disons les choses comme elles sont.", en: "Let's call things as they are.", context: "Calling for bluntness", alt_usage: "Disons les choses comme elles sont : on n'y arrivera pas seuls.", alt_usage_en: "Let's call it like it is: we won't get there alone." },
  // ── New: Daily life ────────────────────────────────────
  { id: 168, fr: "Ça m'est complètement sorti de la tête.", en: "It completely slipped my mind.", context: "Apologizing for forgetting", alt_usage: "Ton anniversaire m'est sorti de la tête, je suis désolé.", alt_usage_en: "Your birthday slipped my mind, I'm sorry." },
  { id: 169, fr: "Je suis débordé en ce moment.", en: "I'm swamped at the moment.", context: "Explaining unavailability", alt_usage: "Je te rappelle plus tard, je suis débordé là.", alt_usage_en: "I'll call you back later, I'm swamped right now." },
  { id: 170, fr: "Ça va me coûter un bras, ce truc.", en: "This thing is going to cost me an arm and a leg.", context: "Reacting to a high price", alt_usage: "Refaire la salle de bain, ça va coûter un bras.", alt_usage_en: "Redoing the bathroom is going to cost an arm and a leg." },
  { id: 171, fr: "On verra ça en temps voulu.", en: "We'll cross that bridge when we come to it.", context: "Deferring a decision", alt_usage: "Pas la peine de s'inquiéter maintenant, on verra ça en temps voulu.", alt_usage_en: "No point worrying now, we'll cross that bridge when we come to it." },
  { id: 172, fr: "Je suis crevé, je vais me coucher.", en: "I'm wiped out, I'm going to bed.", context: "Ending the evening", alt_usage: "Après cette journée, je suis crevé.", alt_usage_en: "After that day, I'm wiped out." },
  { id: 173, fr: "Ça peut attendre demain, non ?", en: "Can't this wait till tomorrow?", context: "Deflecting urgency", alt_usage: "Ce mail peut attendre demain, ne le fais pas ce soir.", alt_usage_en: "That email can wait till tomorrow, don't do it tonight." },
  // ── New: Work & professional ───────────────────────────
  { id: 174, fr: "Je te tiens au courant dès que j'ai du nouveau.", en: "I'll keep you posted as soon as I have news.", context: "Work follow-up", alt_usage: "Je te tiens au courant de l'avancement du dossier.", alt_usage_en: "I'll keep you posted on how the case is progressing." },
  { id: 175, fr: "Ce n'est pas dans mes cordes, désolé.", en: "That's not in my wheelhouse, sorry.", context: "Declining a task", alt_usage: "La compta, ce n'est pas dans mes cordes du tout.", alt_usage_en: "Accounting isn't in my wheelhouse at all." },
  { id: 176, fr: "On fait le point demain matin ?", en: "Shall we touch base tomorrow morning?", context: "Scheduling a sync", alt_usage: "Faisons le point sur le projet avant la réunion.", alt_usage_en: "Let's touch base on the project before the meeting." },
  { id: 177, fr: "Je m'en occupe, ne t'inquiète pas.", en: "I'll handle it, don't worry.", context: "Taking ownership", alt_usage: "Je m'en occupe ce matin, c'est réglé avant midi.", alt_usage_en: "I'll handle it this morning, it'll be sorted before noon." },
  // ── New: Idioms & proverbs ─────────────────────────────
  { id: 178, fr: "Il ne faut pas vendre la peau de l'ours avant de l'avoir tué.", en: "Don't count your chickens before they hatch.", context: "Warning against premature celebration", alt_usage: "Attends la signature avant de fêter ça, ne vends pas la peau de l'ours.", alt_usage_en: "Wait for the signature before celebrating, don't count your chickens." },
  { id: 179, fr: "Petit à petit, l'oiseau fait son nid.", en: "Little by little, the bird builds its nest.", context: "Encouraging patience with gradual progress", alt_usage: "Ne te décourage pas : petit à petit, l'oiseau fait son nid.", alt_usage_en: "Don't get discouraged: little by little, the bird builds its nest." },
  { id: 180, fr: "Qui vivra verra.", en: "Time will tell.", context: "Accepting uncertainty", alt_usage: "Est-ce qu'ils tiendront leur promesse ? Qui vivra verra.", alt_usage_en: "Will they keep their promise? Time will tell." },
  { id: 181, fr: "Chacun voit midi à sa porte.", en: "Everyone sees things from their own perspective.", context: "Acknowledging subjective views", alt_usage: "Inutile de débattre, chacun voit midi à sa porte.", alt_usage_en: "No point debating, everyone sees things their own way." },
  { id: 182, fr: "Les chiens ne font pas des chats.", en: "The apple doesn't fall far from the tree.", context: "Family resemblance", alt_usage: "Il est aussi têtu que son père — les chiens ne font pas des chats.", alt_usage_en: "He's as stubborn as his father — the apple doesn't fall far." },
  { id: 183, fr: "C'est en forgeant qu'on devient forgeron.", en: "Practice makes perfect.", context: "Encouraging perseverance", alt_usage: "Continue à t'entraîner, c'est en forgeant qu'on devient forgeron.", alt_usage_en: "Keep practicing — practice makes perfect." },
  { id: 184, fr: "Mieux vaut tard que jamais.", en: "Better late than never.", context: "Appreciating a delayed action", alt_usage: "Tu m'as enfin répondu — mieux vaut tard que jamais.", alt_usage_en: "You finally answered me — better late than never." },
  { id: 185, fr: "L'habit ne fait pas le moine.", en: "Don't judge a book by its cover.", context: "Warning against appearances", alt_usage: "Il a l'air sévère, mais l'habit ne fait pas le moine.", alt_usage_en: "He looks stern, but don't judge a book by its cover." }
